oxy_webhelp_navlinks = {"configure_ai_connections-d30753e51138":{"topics":[{"title":"Native integrations and cloud platforms","shortdesc":"<p class=\"shortdesc\">Connect AI platforms that have built-in agent capabilities to <span class=\"ph\">Agent Cloud<\/span>. These platforms use cloud-to-cloud integrations that do not require deploying a model         gateway.<\/p>","href":"agent_cloud\/native_integrations_agent_cloud.html","attributes":{"data-id":"native_integrations_agent_cloud"},"menu":{"hasChildren":false},"tocID":"native_integrations_agent_cloud-d30753e51151","next":"native_integrations_agent_cloud-d30753e51151"},{"title":"Endpoint detection in <span class=\"ph\">Agent Cloud<\/span>","shortdesc":"<p class=\"shortdesc\">Endpoint detection connects Agent Cloud to AI agents running on managed devices — desktops and laptops enrolled in an MDM system — so Agent Cloud can monitor their activity.<\/p>","href":"agent_cloud\/endpoint_detection_agent_cloud.html","attributes":{"data-id":"endpoint_detection_agent_cloud"},"menu":{"hasChildren":false},"tocID":"endpoint_detection_agent_cloud-d30753e51581","next":"endpoint_detection_agent_cloud-d30753e51581"},{"title":"Custom agents managed by <span class=\"ph\">Agent Cloud<\/span>","shortdesc":"<p class=\"shortdesc\">If your organization has built AI agents that call LLM APIs directly, connect them to <span class=\"ph\">Agent Cloud<\/span> through a model gateway. A model gateway routes and monitors API traffic between your agents and the LLM, enabling <span class=\"ph\">Agent Cloud<\/span> to enforce policies on custom agent behavior.<\/p>","href":"agent_cloud\/custom_agents_deployed_agent_cloud.html","attributes":{"data-id":"custom_agents_deployed_agent_cloud"},"menu":{"hasChildren":false},"tocID":"custom_agents_deployed_agent_cloud-d30753e51642","next":"custom_agents_deployed_agent_cloud-d30753e51642"}]}};